(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[654],{8486:function(e,i,a){Promise.resolve().then(a.bind(a,7386))},7386:function(e,i,a){"use strict";a.r(i),a.d(i,{default:function(){return o}});var n=a(7437),r=a(601),s=a(3648),t=a(2265);function o(){return(0,n.jsx)("section",{className:"mx-auto mt-8 max-w-[1024px] px-4 sm:px-6 lg:px-0",children:(0,n.jsxs)("div",{className:"prose prose-slate mx-auto max-w-none dark:prose-invert md:prose-lg lg:prose-xl",children:[(0,n.jsx)("h1",{children:"Other Scholarships"}),(0,n.jsxs)("p",{children:["According to Poverty USA, Indigenous Americans experience the highest poverty rates among all ethnic groups, highlighting the great need for financial support. While there is still a shortage of programs, our team at BestColleges.com created a page that highlights several Native American scholarships available to support these underserved students. You can view it here:"," ",(0,n.jsx)(r.O,{isExternal:!0,href:"https://www.bestcolleges.com/financial-aid/native-american-scholarships/",color:"primary",size:"md",children:"https://www.bestcolleges.com/financial-aid/native-american-scholarships/"})]}),[{name:"Harvard University",description:"Harvard University has taken significant strides to make its world-class education accessible to a broader range of students, particularly those from families with limited financial means. Notably, Harvard has implemented a groundbreaking financial aid initiative for families with incomes below $85,000. Under this program, families within this income bracket are not expected to contribute anything towards their child's Harvard education. This initiative reflects Harvard's commitment to ensuring that economic barriers do not impede deserving students from pursuing a top-tier education. By eliminating the financial burden for families in this income range, Harvard aims to encourage talented individuals from diverse backgrounds to benefit from the transformative experience of attending one of the world's leading universities. This proactive approach to financial inclusivity underscores Harvard's dedication to fostering a community of scholars that represents a broad spectrum of socioeconomic backgrounds and enhances the university's mission of advancing knowledge and creating positive societal impact.",url:"https://college.harvard.edu/financial-aid"},{name:"Intertribal Timber Council",description:"The Intertribal Timber Council (ITC) offers a valuable scholarship program aimed at supporting Native American and Alaska Native students pursuing higher education in natural resources-related fields. The ITC scholarship is designed to empower and encourage individuals from indigenous communities to pursue careers in forestry, natural resources management, or other disciplines relevant to the sustainable use and stewardship of tribal forest resources. The scholarship program not only provides financial assistance but also fosters a sense of community and connection among Native students interested in environmental and forestry-related fields. By investing in the education of Native American and Alaska Native students, the Intertribal Timber Council contributes to the development of a skilled and knowledgeable workforce within tribal communities, ensuring that indigenous perspectives play a vital role in the sustainable management of natural resources. This scholarship exemplifies the ITC's commitment to supporting the educational aspirations of Native students and promoting the responsible and culturally sensitive management of tribal lands.",url:"https://www.itcnet.org"},{name:"Carol Jorgensen Scholarship for Environmental Stewardship",description:"This scholarship provides funds to a full time student pursuing an undergraduate degree in an environmental stewardship discipline, including environmental studies, natural resource management, the natural sciences, public administration, public policy, and related disciplines.",url:"https://saige.org/member-resources/scholarships/"},{name:"Internships at the Indian Arts Research Center",description:"The Indian Arts Research Center (IARC) offers three internships annually to Native American, Alaska Native, Native Hawaiian, and First Nations students who are enrolled in undergraduate or graduate programs. Interns work closely with IARC staff and undertake collections-based projects, such as researching the collection, working with artists, developing educational resources, or assisting with an exhibition. Past interns have cataloged the collection, digitized photographs, served as liaison to artists, and conducted research for exhibitions, among other projects. The internships are intended to provide students with opportunities to gain hands-on experience in a museum setting, learn about museum practices, enhance their research skills, and refine career goals.",url:"https://sarweb.org/iarc/internships/"},{name:"American Association of Advertising Agencies (4A) Foundation Scholarships",description:"The 4A Foundation is a nonprofit organization that provides scholarships to multicultural students pursuing a career in advertising. The 4A Foundation offers several scholarships, including the 4A Foundation Multicultural Advertising Intern Program (MAIP) Scholarship, the 4A Foundation Scholars Program, and the 4A Foundation Carolinas Scholarship. The MAIP Scholarship is open to students who have completed their junior year of college and are interested in pursuing a career in advertising. The 4A Foundation Scholars Program is open to students who have completed their sophomore year of college and are interested in pursuing a career in advertising. The 4A Foundation also offers a scholarship for students pursuing a master's degree in advertising.",url:"https://foundation.aaaa.org/scholarshipsawards.html"},{name:"Actuarial Foundation Diversity Scholarship",description:"The Actuarial Foundation offers a scholarship for minority students pursuing a career in actuarial science. The scholarship is open to full-time undergraduate students who are enrolled in a degree program that may lead to a career in the actuarial profession. Applicants must be a member of an underrepresented minority group, including Black/African American, Hispanic, Native North American, or Pacific Islander.",url:"https://actuarialfoundation.org/scholarships/actuarial-diversity-scholarship/"},{name:"American Chemistry Society Scholars Program",description:"The ACS Scholars Program awards renewable scholarships to undergraduate students from historically underrepresented groups in the chemical sciences, majoring in chemistry-related disciplines, and intending to pursue chemistry-related careers. Selected recipients are awarded up to $5,000 per academic year. To date, over 3,500 students have received funding from the ACS Scholars Program.",url:"https://www.acs.org/education/acs-scholars.html"},{name:"AISES (American Indian Science and Engineering Society)",description:"AISES helps students move forward in their educational journeys by providing a wide range of programs and scholarship opportunities. AISES scholarships help students acquire skills and training that will help them meet the unique STEM needs of our communities. AISES scholarships range from $500 to $10,000 and include funding for tuition, books, and academic fees. To be eligible for an AISES scholarship, you must be pursuing a degree in one of the following fields: computer science, engineering, engineering technology, geology, mathematics, natural resources, physical science, or science.",url:"https://www.aises.org/students/scholarships"},{name:"American Indian College Fund",description:"The American Indian College Fund provides scholarships to American Indian and Alaska Native college students seeking undergraduate and graduate degrees at tribal colleges, nonprofit, and accredited schools. The American Indian College Fund also provides scholarships to students attending any other accredited public and non-profit private college all across the United States. The American Indian College Fund also provides scholarships to students attending any other accredited public and non-profit private college all across the United States.",url:"https://collegefund.org/students/scholarship-journey/"},{name:"American Indian Education Foundation",description:"The American Indian Education Foundation (AIEF) provides scholarships to American Indian and Alaska Native undergraduate and graduate students attending tribal colleges and public or private nonprofit colleges across the United States. The AIEF also provides scholarships to students attending any other accredited public and non-profit private college all across the United States.",url:"http://www.nativepartnership.org/site/PageServer?pagename=aief_services_scholarships"},{name:"Native Forward Scholarship Fund",description:"The Native Forward Scholarship Fund is a scholarship program that provides financial support to Native American students pursuing higher education. The scholarship is open to Native American students who are enrolled in a tribe from the continental United States or Alaska. Applicants must be enrolled in an accredited college or university and have a minimum GPA of 2.5. The scholarship is open to students pursuing any degree program, including STEM, business, law, and medicine. The scholarship is open to students pursuing any degree program, including STEM, business, law, and medicine.",url:"https://www.nativeforward.org"},{name:"American Indian Services",description:"American Indian Services (AIS) is a nonprofit organization that provides scholarships to Native American students pursuing higher education. AIS offers scholarships for undergraduate and graduate students attending tribal colleges and public or private nonprofit colleges across the United States. AIS also provides scholarships to students attending any other accredited public and non-profit private college all across the United States.",url:"https://www.americanindianservices.org/scholarships"},{name:"American Nuclear Society",description:"The American Nuclear Society offers a variety of scholarships for students pursuing a degree in nuclear science, nuclear engineering, or a nuclear-related field. The scholarships are open to undergraduate and graduate students. The American Nuclear Society also offers scholarships for high school students who are interested in pursuing a degree in nuclear science, nuclear engineering, or a nuclear-related field.",url:"https://www.ans.org/scholarships/"}].sort((e,i)=>e.name.localeCompare(i.name)).map(e=>(0,n.jsxs)(t.Fragment,{children:[(0,n.jsx)("hr",{}),(0,n.jsx)("h3",{children:e.name}),(0,n.jsx)("p",{children:e.description}),(0,n.jsx)(s.A,{href:e.url,as:r.O,color:"danger",showAnchorIcon:!0,variant:"solid",size:"lg",isExternal:!0,children:e.url})]},e.url))]})})}}},function(e){e.O(0,[723,222,971,472,744],function(){return e(e.s=8486)}),_N_E=e.O()}]);